#include <bits/stdc++.h>
using namespace std;
const int maxn= 5e3+5;
int n,m;
int a[maxn][maxn],t,c,e[maxn][maxn];
bool b[maxn];

void dfs(int x){
	if(!b[x]){
		b[x]=1;
		c++;
		for(int i=1;i<=n;i++){
			if(a[x][i]) dfs(i); 
		}
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		a[x][y]=a[y][x]=1;
	}
	for(int i=1;i<=n;i++){
		for(int j=i+1;j<=n;j++){
			if(a[i][j]){
				a[i][j]=a[j][i]=0;
				fill(b,b+2+n,0);
				c=0;
				dfs(1);
				if(c!=n){
					cout<<i<<" "<<j<<"\n";
				}
				a[i][j]=a[j][i]=1;
			}
		}
	}
	return 0;
}
